import{_ as a,o as r,c as o,ag as i}from"./chunks/framework.D2Ob5GRY.js";const g=JSON.parse('{"title":"什么是 LinScio AI","description":"","frontmatter":{},"headers":[],"relativePath":"intro/what-is-linscio.md","filePath":"intro/what-is-linscio.md"}'),e={name:"intro/what-is-linscio.md"};function n(s,t,l,d,h,c){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="什么是-linscio-ai" tabindex="-1">什么是 LinScio AI <a class="header-anchor" href="#什么是-linscio-ai" aria-label="Permalink to &quot;什么是 LinScio AI&quot;">​</a></h1><blockquote><p>本文帮助你建立对 LinScio AI 产品定位、适用场景与六大功能模块的整体认知。</p></blockquote><h2 id="产品定位与设计理念" tabindex="-1">产品定位与设计理念 <a class="header-anchor" href="#产品定位与设计理念" aria-label="Permalink to &quot;产品定位与设计理念&quot;">​</a></h2><p>LinScio AI（聆思恪）是<strong>学术知识工作者的 AI 思维伙伴</strong>，采用<strong>本地优先、隐私安全、智能降级</strong>原则，在用户本机部署。数据与业务逻辑均在用户环境中运行，可选对接云端 API 与本地 Ollama。</p><p>品牌内核：<strong>聆你所需，思你所问，恪守专业边界</strong>。</p><h2 id="适合哪些用户和场景" tabindex="-1">适合哪些用户和场景 <a class="header-anchor" href="#适合哪些用户和场景" aria-label="Permalink to &quot;适合哪些用户和场景&quot;">​</a></h2><ul><li>高校科研人员：文献管理、论文写作、数据分析、科普转化</li><li>学术机构：团队协作、质量控制、投稿与发表辅助</li><li>需要隐私与合规的场景：数据不出本地，满足机构安全要求</li></ul><h2 id="六大功能模块一览" tabindex="-1">六大功能模块一览 <a class="header-anchor" href="#六大功能模块一览" aria-label="Permalink to &quot;六大功能模块一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>能力概要</th></tr></thead><tbody><tr><td><strong>文献管理（Literature）</strong></td><td>PDF 上传与解析、元数据/全文提取、多格式引用、文献综述、向量化与语义检索</td></tr><tr><td><strong>论文写作（Schola）</strong></td><td>选题评估、开题报告、大纲设计、章节写作、学术规范检查、投稿辅助</td></tr><tr><td><strong>科普创作（MedComm）</strong></td><td>选题与调研、素材整合、事实核查、多平台适配（微信、知乎、小红书等）</td></tr><tr><td><strong>数据分析（Data Analyzer）</strong></td><td>数据上传、分析规划、数据清洗、统计方法推荐、代码生成、可视化与结果解读</td></tr><tr><td><strong>质控工具（QCC）</strong></td><td>鱼骨图、5Why、柏拉图、改进方案与 PDCA 管理</td></tr><tr><td><strong>AI Image Studio</strong></td><td>学术图表美化、示意图生成、海报与汇报插图</td></tr></tbody></table><h2 id="私有化部署的优势-为什么不是云端-saas" tabindex="-1">私有化部署的优势：为什么不是云端 SaaS <a class="header-anchor" href="#私有化部署的优势-为什么不是云端-saas" aria-label="Permalink to &quot;私有化部署的优势：为什么不是云端 SaaS&quot;">​</a></h2><ul><li><strong>数据本地存储</strong>：文献、写作内容、分析数据均保存在用户自己的服务器或机器上，满足数据合规与隐私要求。</li><li><strong>可离线使用</strong>：配置本地 Ollama 后，核心能力可在内网或离线环境使用。</li><li><strong>可控可审计</strong>：部署方完全掌握访问权限、日志与更新节奏。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/intro/system-requirements.html">系统要求</a></li><li><a href="/docs/quickstart/overview.html">快速开始</a></li></ul>',13)])])}const m=a(e,[["render",n]]);export{g as __pageData,m as default};
